import{_ as t,o as e,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"F05: 應收帳款品質與收款天數 - 財務審計專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3163_波若威/20260502/F05_應收帳款品質與收款天數.md","filePath":"審計報告庫/財務審計/3163_波若威/20260502/F05_應收帳款品質與收款天數.md"}'),i={name:"審計報告庫/財務審計/3163_波若威/20260502/F05_應收帳款品質與收款天數.md"};function l(n,a,s,h,d,_){return e(),r("div",null,[...a[0]||(a[0]=[o('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f05-應收帳款品質與收款天數-財務審計專家-審計報告" tabindex="-1">F05: 應收帳款品質與收款天數 - 財務審計專家 審計報告 <a class="header-anchor" href="#f05-應收帳款品質與收款天數-財務審計專家-審計報告" aria-label="Permalink to &quot;F05: 應收帳款品質與收款天數 - 財務審計專家 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>應收帳款 (AR) 的規模與週轉天數 (DSO) 變動為何？是否存在客戶拖欠或虛增營收風險？</p><h2 id="🎯-專家直斷-62-字" tabindex="-1">🎯 專家直斷（62 字） <a class="header-anchor" href="#🎯-專家直斷-62-字" aria-label="Permalink to &quot;🎯 專家直斷（62 字）&quot;">​</a></h2><ul><li><strong>核心結論</strong>：波若威 AR 管理紀律嚴謹，2022→2025 年 AR 總額由 7.60 億縮至 4.83 億（-36%），92% 帳款未逾期，DSO 從 86 天優化至 81 天，惟 2024 年 DSO 跳升至 83 天反映營收急凍下 AR 去化速度追不上營收滑坡。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：根據截至 2025 年最新公開數據</li></ul><h2 id="📊-診斷評級-112-字" tabindex="-1">📊 診斷評級（112 字） <a class="header-anchor" href="#📊-診斷評級-112-字" aria-label="Permalink to &quot;📊 診斷評級（112 字）&quot;">​</a></h2><p>DSO 四年分別為 86→63→83→81 天，2023 年顯著改善至 63 天（主因營收衰退期積極回收 AR 2.81 億），2024-2025 年回落至 81-83 天與營收底部盤整相符。帳齡結構極度健康：2025 年 91.7% 應收帳款未逾期，僅 0.9% 逾期 31-90 天（452 萬），無任何呆帳準備提列歷史。客戶集中度中等（前三大佔營收約 50%），其中 J 客戶（4.33 億/20%）與 C 客戶（3.87 億/18%）為主要貢獻來源。</p><h2 id="🔍-答詢詳解-387-字" tabindex="-1">🔍 答詢詳解（387 字） <a class="header-anchor" href="#🔍-答詢詳解-387-字" aria-label="Permalink to &quot;🔍 答詢詳解（387 字）&quot;">​</a></h2><h3 id="一、收款天數實測-dso-波動與營收週期高度同步" tabindex="-1">一、收款天數實測：DSO 波動與營收週期高度同步 <a class="header-anchor" href="#一、收款天數實測-dso-波動與營收週期高度同步" aria-label="Permalink to &quot;一、收款天數實測：DSO 波動與營收週期高度同步&quot;">​</a></h3><p>DSO 從 2022 年 86 天降至 2023 年 63 天（優化 23 天），與當年營收衰退 15% 同時 AR 大幅回收 2.81 億的積極收款行動一致。2024 年 DSO 回升至 83 天（惡化 20 天），主因為營收年減 25.9% 的速度（2.75 億→2.04 億）遠快於 AR 降幅（4.79 億→4.65 億，-3%）。這是「分母效應」而非收款惡化——客戶付款行為未變，但營收基期急縮使 DSO 被動拉高。2025 年營收反彈 6.1% 後 DSO 略降至 81 天，確認 AR 品質未受結構性損害。</p><h3 id="二、帳齡分析-無逾期風險-呆帳提列為零" tabindex="-1">二、帳齡分析：無逾期風險，呆帳提列為零 <a class="header-anchor" href="#二、帳齡分析-無逾期風險-呆帳提列為零" aria-label="Permalink to &quot;二、帳齡分析：無逾期風險，呆帳提列為零&quot;">​</a></h3><p>2025 年年報揭露（P26）：未逾期 AR 4.43 億（佔 91.7%）、逾期 1-30 天 3,577 萬（7.4%）、逾期 31-90 天僅 452 萬（0.9%）。預期損失率設定極低（未逾期 0.03%、逾期 31-90 天僅 0.04%），且備抵損失為零。對比 2024 年：未逾期佔 88%、逾期 1-30 天 12%、無 31-90 天逾期。帳齡結構反而略有改善（2025 年逾期 30 天內佔比下降，且 31-90 天僅 452 萬）。過去四年無任何應收帳款呆帳沖銷記錄。</p><h3 id="三、客戶集中度-前三大客戶佔比偏高中等風險" tabindex="-1">三、客戶集中度：前三大客戶佔比偏高中等風險 <a class="header-anchor" href="#三、客戶集中度-前三大客戶佔比偏高中等風險" aria-label="Permalink to &quot;三、客戶集中度：前三大客戶佔比偏高中等風險&quot;">​</a></h3><p>前三大客戶 J（4.33 億/20%）、C（3.87 億/18%）、F（2.50 億/12%）合計貢獻 2025 年營收約 50%。其中 C 客戶營收從 2024 年 4.96 億降至 2025 年 3.87 億（-22%），反映電信客戶需求減弱。J 客戶則從 3.41 億升至 4.33 億（+27%），推測為 AI/DC 相關客戶。雖無單一客戶佔比 &gt;25% 的過度集中風險，但任一主要客戶訂單變動仍將顯著影響營收穩定性。</p><h2 id="💡-專家評析-257-字" tabindex="-1">💡 專家評析（257 字） <a class="header-anchor" href="#💡-專家評析-257-字" aria-label="Permalink to &quot;💡 專家評析（257 字）&quot;">​</a></h2><ol><li><p><strong>AR 管理為經營亮點，但 DSO 已難再優化</strong>：公司過去四年在營收持續下滑的逆境中仍能降低 AR 絕對金額 36%，展現營運資金管控能力。但目前 DSO 約 81 天已處於行業正常區間下緣，未來隨著 AI 產品出貨增加可能因新客戶條件較寬鬆而小幅回升，進一步改善空間有限。</p></li><li><p><strong>零呆帳準備的雙面性</strong>：年度備抵損失為零雖反映優秀的收款記錄，但在 IFRS 9 預期損失模型下，對應收帳款完全不提列備抵損失可能偏於激進。若未來新增大型客戶或市場轉向，一次性信用損失將直接侵蝕淨利，特別是當前客戶集中度偏高（前三大佔 50%）的結構下。</p></li><li><p><strong>2024 年 DSO 跳升的隱藏成本</strong>：2024 年 DSO 由 63 天急升至 83 天，雖然主因為分母效應而非收款惡化，但公司為維持現金流承受了顯著壓力：CFO 轉負（-1.34 億）、應付帳款被大幅壓縮至 2.20 億——<strong>犧牲供應商付款來維持客戶收款條件的平衡策略</strong>。</p></li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>計算工具</strong>：財務分析工具.py (receivable_check 3163 2022 2025)</li><li><strong>原始數據</strong>：FinMind TaiwanStockBalanceSheet, TaiwanStockMonthRevenue</li><li><strong>年報 PDF</strong>：2025 Q4 合併財務報告 P26（應收帳款帳齡分析）、P42（預期信用損失）、P48（重要客戶資訊）</li><li><strong>查詢參數</strong>：stock_id=3163, start=2022-01-01, end=2025-12-31</li><li><strong>關鍵核對碼</strong>：DSO(天) 2022=86→2023=63→2024=83→2025=81；AR淨額(百萬) 2022=760→2023=479→2024=465→2025=483；未逾期佔比% 2025=91.7</li></ul>',19)])])}const u=t(i,[["render",l]]);export{p as __pageData,u as default};
